class StripePaymentService implements PaymentService {
  final String publishableKey;
  final String backendBaseUrl;

  StripePaymentService({
    required this.publishableKey,
    required this.backendBaseUrl,
  }) {
    Stripe.publishableKey = publishableKey;
    Stripe.instance.applySettings();
  }

  @override
  Future<PaymentResult> makePayment({
    required String amount,
    required String currency,
    required String description,
  }) async {
    try {
      final response = await http.post(
        Uri.parse('$backendBaseUrl/create-payment-intent'),
        headers: {'Content-Type': 'application/json'},
        body: json.encode({
          'amount': (double.parse(amount) * 100).toInt(),
          'currency': currency.toLowerCase(),
          'description': description,
        }),
      );

      final responseBody = json.decode(response.body);
      if (response.statusCode != 200 || responseBody['error'] != null) {
        return PaymentResult(PaymentStatus.failed, message: responseBody['error'] ?? 'Backend error');
      }

      final paymentIntentClientSecret = responseBody['paymentIntent'];
      final ephemeralKeySecret = responseBody['ephemeralKey'];
      final customerId = responseBody['customer'];

      await Stripe.instance.initPaymentSheet(
        paymentSheetParameters: SetupPaymentSheetParameters(
          merchantDisplayName: 'Your Company Name',
          paymentIntentClientSecret: paymentIntentClientSecret,
          customerEphemeralKeySecret: ephemeralKeySecret,
          customerId: customerId,
          style: ThemeMode.light,
          applePay: PaymentSheetApplePay(merchantCountryCode: 'US'),
          googlePay: PaymentSheetGooglePay(merchantCountryCode: 'US', testEnv: true),
        ),
      );

      await Stripe.instance.presentPaymentSheet();

      return PaymentResult(PaymentStatus.success, transactionId: paymentIntentClientSecret, message: 'Payment successful');

    } on StripeException catch (e) {
      if (e.error.code == 'Canceled') {
        return PaymentResult(PaymentStatus.cancelled, message: 'Payment cancelled by user');
      }
      return PaymentResult(PaymentStatus.failed, message: 'Payment failed: ${e.error.message}');
    } catch (e) {
      return PaymentResult(PaymentStatus.failed, message: 'An unexpected error occurred: ${e.toString()}');
    }
  }

