  final StreamController<List<PurchaseDetails>> _purchaseUpdatesController = StreamController.broadcast();

  final String backendVerifyPurchaseUrl;

  InAppPurchaseService({required this.backendVerifyPurchaseUrl});

  @override
  Future<void> initializeInAppPurchases() async {
    final bool available = await _inAppPurchase.isAvailable();
    if (!available) {
      return;
    }

    if ( _inAppPurchase.presentPlatform.runtimeType == InAppPurchaseStoreKitPlatform ||
         _inAppPurchase.presentPlatform.runtimeType == InAppPurchaseGooglePlayPlatform) {
      _purchaseStreamSubscription = _inAppPurchase.purchaseStream.listen(
        (purchaseDetailsList) {
          _purchaseUpdatesController.add(purchaseDetailsList);
          _handlePurchaseUpdates(purchaseDetailsList);
        },
        onDone: () {
          _purchaseUpdatesController.close();
          _purchaseStreamSubscription.cancel();
        },
        onError: (error) {
          _purchaseUpdatesController.addError(error);
        },
      );
    } else {
    }

    if (_inAppPurchase.presentPlatform is InAppPurchaseStoreKitPlatform) {
      final InAppPurchaseStoreKitPlatform iapSKPlatform = _inAppPurchase.presentPlatform as InAppPurchaseStoreKitPlatform;
      await iapSKPlatform.restorePurchases();
    }
  }

  void _handlePurchaseUpdates(List<PurchaseDetails> purchaseDetailsList) {
    for (final PurchaseDetails purchaseDetails in purchaseDetailsList) {
      if (purchaseDetails.status == PurchaseStatus.pending) {
      } else {
        if (purchaseDetails.status == PurchaseStatus.error) {
        } else if (purchaseDetails.status == PurchaseStatus.purchased ||
                   purchaseDetails.status == PurchaseStatus.restored) {
          _verifyPurchase(purchaseDetails).then((verified) {
            if (verified) {
              completePurchase(purchaseDetails);
            } else {
            }
          });
        }
      }
    }
  }

  Future<bool> _verifyPurchase(PurchaseDetails purchaseDetails) async {
    try {
      final response = await http.post(
        Uri.parse(backendVerifyPurchaseUrl),
        headers: {'Content-Type': 'application/json'},
        body: json.encode({
          'platform': _inAppPurchase.presentPlatform.runtimeType.toString(),
          'purchaseToken': purchaseDetails.verificationData.serverVerificationData,
          'productId': purchaseDetails.productID,
          'transactionId': purchaseDetails.transactionID,
        }),
      );

      if (response.statusCode == 200) {
        final responseBody = json.decode(response.body);
        return responseBody['isValid'] == true;
      } else {
        return false;
      }
    } catch (e) {
      return false;
    }
  }

  @override
  Stream<List<PurchaseDetails>> getInAppPurchaseUpdates() => _purchaseUpdatesController.stream;

  @override
  Future<List<ProductDetails>> getInAppProducts(Set<String> productIds) async {
    final ProductDetailsResponse response = await _inAppPurchase.queryProductDetails(productIds);
    if (response.error != null) {
      return [];
    }
    return response.productDetails;
  }

  @override
  Future<void> purchaseProduct(ProductDetails product) async {
    final PurchaseParam purchaseParam = PurchaseParam(productDetails: product);
    if (product.id.contains('sub')) {
      _inAppPurchase.buyNonConsumable(purchaseParam: purchaseParam);
    } else {
      _inAppPurchase.buyConsumable(purchaseParam: purchaseParam);
    }
  }

  @override
  Future<void> completePurchase(PurchaseDetails purchase) async {
    if (purchase.pendingCompletePurchase) {
      await _inAppPurchase.completePurchase(purchase);
    }
  }

  void dispose() {
    _purchaseStreamSubscription.cancel();
    _purchaseUpdatesController.close();
  }

