class MobileWalletPaymentService implements PaymentService {
  final String merchantIdentifier;
  final String backendBaseUrl;
  final String stripePublishableKey; // Required if using Stripe as gateway for pay package

  MobileWalletPaymentService({
    required this.merchantIdentifier,
    required this.backendBaseUrl,
    required this.stripePublishableKey,
  });

  @override
  Future<PaymentResult> makePayment({
    required String amount,
    required String currency,
    required String description,
  }) async {
    List<PaymentItem> paymentItems = [
      PaymentItem(
        label: description,
        amount: amount,
        status: PaymentItemStatus.final_price,
      ),
    ];

    try {
      final PaymentConfiguration paymentConfiguration = PaymentConfiguration.fromJsonString(
        '''{
          "provider": "google_pay",
          "data": {
            "environment": "TEST",
            "apiVersion": 2,
            "apiVersionMinor": 0,
            "allowedPaymentMethods": [
              {
                "type": "CARD",
                "parameters": {
                  "allowedAuthMethods": ["PAN_ONLY", "CRYPTOGRAM_3DS"],
                  "allowedCardNetworks": ["AMEX", "VISA", "MASTERCARD", "DISCOVER"]
                },
                "tokenizationSpecification": {
                  "type": "PAYMENT_GATEWAY",
                  "parameters": {
                    "gateway": "stripe",
                    "stripe:version": "2020-08-27",
                    "stripe:publishableKey": "$stripePublishableKey"
                  }
                }
              }
            ],
            "merchantInfo": {
              "merchantName": "Your Company Name",
              "merchantId": "01234567890123456789"
            },
            "transactionInfo": {
              "countryCode": "US",
              "currencyCode": "$currency",
              "totalPriceStatus": "FINAL",
              "totalPrice": "$amount"
            }
          }
        }'''
      );

      final result = await Pay.showPaymentSelector(
        provider: PayProvider.google_pay,
        paymentConfiguration: paymentConfiguration,
        paymentItems: paymentItems,
        style: PayButtonStyle.black,
        type: PayButtonType.buy,
        onPaymentResult: (paymentResult) async {
          final Map<String, dynamic> tokenData = json.decode(paymentResult['paymentMethodData']['tokenizationData']['token']);
          final String paymentToken = tokenData['id'] ?? tokenData['token'];

          try {
            final backendResponse = await http.post(
              Uri.parse('$backendBaseUrl/process-mobile-wallet-payment'),
              headers: {'Content-Type': 'application/json'},
              body: json.encode({
                'paymentToken': paymentToken,
                'amount': (double.parse(amount) * 100).toInt(),
                'currency': currency,
                'description': description,
              }),
            );

            if (backendResponse.statusCode == 200) {
              final backendResponseBody = json.decode(backendResponse.body);
              if (backendResponseBody['success'] == true) {
                return PaymentResult(
                  PaymentStatus.success,
                  transactionId: backendResponseBody['transactionId'],
                  message: 'Payment processed successfully via mobile wallet.',
                );
              } else {
                return PaymentResult(PaymentStatus.failed, message: backendResponseBody['message'] ?? 'Backend failed to process mobile wallet payment.');
              }
            } else {
              return PaymentResult(PaymentStatus.failed, message: 'Backend communication error: ${backendResponse.statusCode}');
            }
          } catch (e) {
            return PaymentResult(PaymentStatus.failed, message: 'Error processing mobile wallet payment on backend: $e');
          }
        },
      );

      return PaymentResult(PaymentStatus.pending, message: 'Payment initiated via mobile wallet. Awaiting backend confirmation.');

    } on Exception catch (e) {
      if (e is UserCancelledException) {
        return PaymentResult(PaymentStatus.cancelled, message: 'Mobile wallet payment cancelled.');
      }
      return PaymentResult(PaymentStatus.failed, message: 'Mobile wallet payment failed: ${e.toString()}');
    }
  }

